(function() {
  'use strict';

  const $ = window.jQuery;

  const CONFIG = {
    cssStyles: `.nv5-wrap{margin:16px 0;font-family:"Segoe UI",system-ui,-apple-system,sans-serif;font-size:0.92em;background:rgba(35,28,42,0.52);backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);border:1px solid rgba(140,115,170,0.22);border-radius:16px;overflow:hidden;box-shadow:0 6px 30px rgba(60,40,80,0.18);color:#ede8f2}.nv5-wrap *{box-sizing:border-box;margin:0;padding:0}.nv5-header{padding:12px 16px;background:rgba(60,45,75,0.38);border-bottom:1px solid rgba(140,115,170,0.18);display:flex;flex-direction:column;align-items:stretch;gap:10px}.nv5-loc{font-weight:700;font-size:1.02em;color:#f0eaf5;display:flex;align-items:flex-start;gap:8px;min-width:0;line-height:1.35;text-align:left}.nv5-loc-text{flex:1 1 auto;min-width:0;white-space:normal;overflow-wrap:anywhere;word-break:break-word;text-align:left;text-justify:auto;word-spacing:normal;letter-spacing:normal}.nv5-icon{flex:0 0 auto;line-height:1.2}.nv5-meta{font-size:0.86em;color:#cdc0d8;font-weight:500;display:flex;align-items:flex-start;gap:8px 14px;flex-wrap:wrap;min-width:0;text-align:left}.nv5-meta-item{display:flex;align-items:flex-start;gap:4px;min-width:0;white-space:normal;overflow-wrap:anywhere;word-break:break-word;text-align:left;text-justify:auto;word-spacing:normal;letter-spacing:normal}.nv5-section{border-top:1px solid rgba(140,115,170,0.15)}.nv5-section input[type=checkbox]{display:none}.nv5-sec-header{padding:10px 16px;background:rgba(55,42,68,0.32);cursor:pointer;display:flex;justify-content:space-between;align-items:center;transition:background 0.2s;user-select:none}.nv5-sec-header:hover{background:rgba(70,52,88,0.42)}.nv5-sec-title{font-weight:700;font-size:0.86em;text-transform:uppercase;letter-spacing:1.5px;color:#d8cee5;display:flex;align-items:center;gap:6px}.nv5-sec-arrow{color:#b0a0c0;font-size:0.7em;transition:transform 0.3s ease}.nv5-sec-body{max-height:0;overflow:hidden;transition:max-height 0.4s cubic-bezier(0.4,0,0.2,1),padding 0.3s;padding:0 14px;background:rgba(0,0,0,0.06)}.nv5-section input:checked~.nv5-sec-body{max-height:5000px;padding:12px 14px}.nv5-section input:checked~.nv5-sec-header .nv5-sec-arrow{transform:rotate(180deg)}.nv5-char{background:rgba(70,55,88,0.28);border:1px solid rgba(140,115,170,0.16);border-radius:10px;padding:11px 13px;margin-bottom:9px;transition:background 0.2s}.nv5-char:last-child{margin-bottom:0}.nv5-char:hover{background:rgba(80,62,100,0.35)}.nv5-char-away{opacity:0.45}.nv5-char-nearby{opacity:0.7}.nv5-char-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;padding-bottom:7px;border-bottom:1px solid rgba(140,115,170,0.12);gap:10px;min-width:0}.nv5-char-name{font-weight:700;font-size:0.98em;color:#f2ecf7;display:flex;align-items:flex-start;gap:5px;min-width:0;overflow-wrap:anywhere;word-break:break-word;text-align:left}.nv5-char-status{font-size:0.76em;color:#b0a0c0;text-transform:uppercase;letter-spacing:0.9px;font-weight:600;flex:0 0 auto}.nv5-char-grid{display:grid;grid-template-columns:1fr 1fr;gap:7px 12px}.nv5-field{display:flex;flex-direction:column;gap:2px;min-width:0}.nv5-label{font-size:0.76em;color:#a898b8;font-weight:600;text-transform:uppercase;letter-spacing:0.7px}.nv5-value{font-size:0.88em;color:#e5dced;line-height:1.4;font-weight:500;white-space:normal;overflow-wrap:anywhere;word-break:break-word;text-align:left;text-justify:auto;word-spacing:normal}.nv5-feelings{font-style:italic;color:#d0c4de;font-weight:400}.nv5-field:nth-child(4){grid-column:1/-1}.nv5-thought{margin-top:8px;padding:9px 12px;background:rgba(55,40,72,0.32);border-left:3px solid rgba(150,120,190,0.4);border-radius:0 9px 9px 0}.nv5-thought-label{font-size:0.76em;color:#a898b8;font-weight:600;text-transform:uppercase;letter-spacing:0.7px;display:block;margin-bottom:3px}.nv5-thought-text{font-size:0.88em;color:#e0d6ea;font-style:italic;line-height:1.5;font-weight:400;white-space:normal;overflow-wrap:anywhere;word-break:break-word;text-align:left;text-justify:auto;word-spacing:normal}@media(max-width:480px){.nv5-char-grid{grid-template-columns:1fr}.nv5-header{padding:12px 14px}.nv5-sec-header{padding:10px 14px}.nv5-char-header{flex-direction:column;align-items:flex-start}}`,
    mainRegex: /◈NORICORE◈([\s\S]*?)◈\/NORICORE◈/gi
  };

  let TH = null;
  const statusIcon = { present: '🟢', nearby: '🟡', away: '⚫' };

  function healthIcon(h) {
    if (!h) return '💚';
    const l = h.toLowerCase();
    if (l === 'fine' || l === '—') return '💚';
    if (l.includes('critical')) return '🔴';
    if (l.includes('serious')) return '🟠';
    if (l.includes('moderate')) return '🟡';
    return '🩹';
  }

  function healthColor(h) {
    if (!h) return '#a0b8a0';
    const l = h.toLowerCase();
    if (l === 'fine' || l === '—') return '#a0c8a0';
    if (l.includes('critical')) return '#c87070';
    if (l.includes('serious')) return '#c8a070';
    if (l.includes('moderate')) return '#c8c080';
    return '#a0c8a0';
  }

  function parse(text) {
    const data = { scene: null, chars: [] };
    const sm = text.match(/⟪SCENE⟫([^⟫]+)⟫/);
    if (sm) {
      const p = sm[1].split('|').map(s => s.trim());
      data.scene = { location: p[0] || '—', weather: p[1] || '—', date: p[2] || '—', time: p[3] || '—' };
    }
    const rx = /⟪CHAR⟫([^⟫]+)⟫/g;
    let m;
    while ((m = rx.exec(text)) !== null) {
      const p = m[1].split('|').map(s => s.trim());
      if (p[0]) data.chars.push({ name: p[0], status: p[1] || 'present', outfit: p[2] || '—', health: p[3] || 'Fine', mood: p[4] || '—', feelings: p[5] || '—', thoughts: p[6] || '' });
    }
    return data;
  }

  function render(data) {
    if (!data.scene || !data.chars.length) return null;
    const uid = 'nv' + Math.random().toString(36).substr(2, 8);
    const s = data.scene;
    let cards = '';
    for (let i = 0; i < data.chars.length; i++) {
      const c = data.chars[i];
      const statusLower = (c.status || '').toLowerCase();
      const si = statusIcon[statusLower] || '⚪';
      const oc = statusLower === 'away' ? 'nv5-char-away' : statusLower === 'nearby' ? 'nv5-char-nearby' : '';
      const hi = healthIcon(c.health);
      const hc = healthColor(c.health);
      const hasT = c.thoughts && c.thoughts !== '—' && c.thoughts.length > 0;
      cards += '<div class="nv5-char ' + oc + '"><div class="nv5-char-header"><div class="nv5-char-name">' + si + ' ' + c.name + '</div><div class="nv5-char-status">' + c.status + '</div></div>';
      cards += '<div class="nv5-char-grid"><div class="nv5-field"><span class="nv5-label">👗 OUTFIT</span><span class="nv5-value">' + c.outfit + '</span></div><div class="nv5-field"><span class="nv5-label">' + hi + ' HEALTH</span><span class="nv5-value" style="color:' + hc + '">' + c.health + '</span></div><div class="nv5-field"><span class="nv5-label">🎭 MOOD</span><span class="nv5-value">' + c.mood + '</span></div><div class="nv5-field"><span class="nv5-label">💜 FEELINGS</span><span class="nv5-value nv5-feelings">' + c.feelings + '</span></div></div>';
      if (hasT) cards += '<div class="nv5-thought"><span class="nv5-thought-label">💭 THOUGHTS</span><div class="nv5-thought-text">' + c.thoughts + '</div></div>';
      cards += '</div>';
    }
    return '<div class="nv5-wrap"><div class="nv5-header"><div class="nv5-loc"><span class="nv5-icon">📍</span><span class="nv5-loc-text">' + s.location + '</span></div><div class="nv5-meta"><span class="nv5-meta-item"><span class="nv5-icon">🌤️</span><span>' + s.weather + '</span></span><span class="nv5-meta-item"><span class="nv5-icon">📅</span><span>' + s.date + '</span></span><span class="nv5-meta-item"><span class="nv5-icon">🕐</span><span>' + s.time + '</span></span></div></div><div class="nv5-section"><input type="checkbox" id="' + uid + '"><label for="' + uid + '" class="nv5-sec-header"><span class="nv5-sec-title">👥 CHARACTERS (' + data.chars.length + ')</span><span class="nv5-sec-arrow">▼</span></label><div class="nv5-sec-body">' + cards + '</div></div></div>';
  }

  function updateMessageVisuals(messageId, _retry = false) {
    if (!TH) return;

    let messageContent = null;
    try {
      const msgsWithSwipes = TH.getChatMessages(messageId, { include_swipes: true });
      if (msgsWithSwipes && msgsWithSwipes.length > 0) {
        const m = msgsWithSwipes[0];
        messageContent = (m.swipes && m.swipes.length > 0) ? (m.swipes[m.swipe_id ?? 0] ?? m.swipes[0]) : m.message;
      }
    } catch (_) { }
    if (!messageContent) {
      const msgs = TH.getChatMessages(messageId);
      if (!msgs || msgs.length === 0) return;
      messageContent = msgs[0].message;
    }
    if (!messageContent) return;

    const $mes = TH.retrieveDisplayedMessage(messageId);
    if (!$mes || !$mes.length) return;
    const $target = $mes.find('.mes_text').length ? $mes.find('.mes_text') : $mes;
    let htmlContent = $target.html();
    if (!htmlContent) return;

    const regex = new RegExp(CONFIG.mainRegex.source, 'gi');
    const matches = [...htmlContent.matchAll(regex)];
    if (matches.length === 0) {
      if (!_retry) setTimeout(() => updateMessageVisuals(messageId, true), 300);
      return;
    }

    let newHtml = htmlContent;
    for (let i = matches.length - 1; i >= 0; i--) {
      const match = matches[i];
      const text = match[1];
      const data = parse(text);
      const widget = render(data);
      if (widget) {
        newHtml = newHtml.substring(0, match.index) + widget + newHtml.substring(match.index + match[0].length);
      }
    }

    if (newHtml !== htmlContent) {
      $target.html(newHtml);
    }
  }

  function initializeScript() {
    if (!window.TavernHelper || !window.tavern_events || typeof window.eventOn !== 'function') {
      setTimeout(initializeScript, 200);
      return;
    }

    TH = window.TavernHelper;
    const events = window.tavern_events;

    if (!$('#nv5-styles').length) {
      $('head').append('<style id="nv5-styles">' + CONFIG.cssStyles + '</style>');
    }

    window.eventOn(events.CHARACTER_MESSAGE_RENDERED, (id) => setTimeout(() => updateMessageVisuals(id), 150));
    window.eventOn(events.USER_MESSAGE_RENDERED, (id) => setTimeout(() => updateMessageVisuals(id), 150));

    const onMessageEdited = (messageId) => setTimeout(() => updateMessageVisuals(messageId), 0);
    window.eventOn(events.MESSAGE_EDITED, onMessageEdited);
    window.eventOn(events.MESSAGE_UPDATED, onMessageEdited);
    window.eventOn(events.MESSAGE_SWIPED, (messageId) => setTimeout(() => updateMessageVisuals(messageId), 0));

    const scanMessages = () => {
      $('.mes').each(function() {
        const id = $(this).attr('mesid');
        if (id) updateMessageVisuals(Number(id));
      });
    };
    scanMessages();

    window.eventOn(events.CHAT_CHANGED, () => setTimeout(scanMessages, 500));
    window.eventOn(events.MORE_MESSAGES_LOADED, scanMessages);

    console.log('[NoriVoid] ✨ Initialized');
  }

  $(document).ready(initializeScript);
})();
